async function extractTextFromPDF(dataBase64) {
  try {
    const loadingTask = pdfjsLib.getDocument({ data: atob(dataBase64) });
    const pdf = await loadingTask.promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) { const page = await pdf.getPage(i); const textContent = await page.getTextContent(); fullText += textContent.items.map(item => item.str).join(' ') + "\n"; }
    return fullText.trim();
  } catch (e) { return null; }
}

async function extract(){
  const p = ST.config.provider || 'auto';
  const hasKey = (p==='auto' && (ST.config.has_api_key || ST.config.has_gemini_key || ST.config.has_openai_key)) || (p==='anthropic' && ST.config.has_api_key) || (p==='google' && ST.config.has_gemini_key) || ((p==='openai'||p==='groq') && ST.config.has_openai_key);
  if(!hasKey){sb('Configura al menos una API Key en la pestaña Configuración','err'); return;}
  if(!ST.files.length){sb('Sube al menos un archivo','err');return;}
  $('btnEx').disabled=true; sb('Analizando factura con IA ('+p.toUpperCase()+')…','load');
  const uc=[];
  for(const f of ST.files){
    let textContent = null; const m = f.type || 'image/jpeg';
    if(m.includes('pdf')) textContent = await extractTextFromPDF(f.data);
    if(textContent && textContent.length > 50){ uc.push({type:'text', text: "TEXTO DEL DOC:\n" + textContent}); }
    else { uc.push(m.includes('pdf') ?{type:'document',source:{type:'base64',media_type:'application/pdf',data:f.data}} :{type:'image',source:{type:'base64',media_type:m,data:f.data}}); }
  }
  const prompt='Extrae los datos de la factura en JSON:\n{"cliente":"","cups":"","comercializadora":"","direccion":"","cp":"","tarifa":"","potencia_kw":0,"dias":0,"fecha_inicio":"","total_factura":0,"iva_pct":21,"iee_pct":5.1126963,"iee_act":0,"iva_act":0,"dto_energia_act_pct":0,"tiene_autoconsumo":false,"autoconsumo_kwh":0,"autoconsumo_precio_kwh":0,"autoconsumo_total":0,"potencia":[],"energia":[],"lecturas_energia":[],"reactiva":0,"exceso_potencia":0,"alquiler_equipos":0,"bono_social":0,"servicio":0}';
  uc.push({type:'text',text:prompt});
  try{
    const resp=await fetch('/api/extract',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({messages:[{role:'user',content:uc}]})});
    const d=await resp.json(); if(d.error) throw new Error(d.error);
    let cleanText = d.text || ""; const firstBrace = cleanText.indexOf('{'); const lastBrace = cleanText.lastIndexOf('}');
    if(firstBrace !== -1 && lastBrace !== -1){ cleanText = cleanText.substring(firstBrace, lastBrace + 1); }
    const ex = JSON.parse(cleanText); fillForm(ex); sb('Completado ✓','ok'); go('rev');
  }catch(e){ sb('Error: '+e.message,'err'); }finally{ $('btnEx').disabled=false; }
}

